mapper.update:
update auth_oauth_accounts
set email_at_provider = #{emailAtProvider},
    display_name_at_provider = #{displayNameAtProvider},
    avatar_url_at_provider = #{avatarUrlAtProvider},
    updated_at = #{updatedAt}
where id = #{accountId}

update auth_users
set last_login_at = #{lastLoginAt},
    updated_at = #{lastLoginAt}
where id = #{userId}
